import{_ as a,c as n,o as t,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"Multi-Channel and Platform Integration","description":"Learn how to configure and use Clawdbot's multi-channel system, including WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS, and Android platforms.","frontmatter":{"title":"Multi-Channel and Platform Integration","sidebarTitle":"Platforms and Channels","subtitle":"Multi-Channel and Platform Integration","description":"Learn how to configure and use Clawdbot's multi-channel system, including WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS, and Android platforms.","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"moltbot/moltbot/platforms/index.md","filePath":"moltbot/moltbot/platforms/index.md"}`),i={name:"moltbot/moltbot/platforms/index.md"};function r(s,e,l,c,d,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="multi-channel-and-platform-integration" tabindex="-1">Multi-Channel and Platform Integration <a class="header-anchor" href="#multi-channel-and-platform-integration" aria-label="Permalink to &quot;Multi-Channel and Platform Integration&quot;">​</a></h1><p>Clawdbot supports multiple communication channels and platforms through a unified Gateway control plane, enabling you to interact with your AI assistant on the interface you&#39;re familiar with.</p><h2 id="chapter-overview" tabindex="-1">Chapter Overview <a class="header-anchor" href="#chapter-overview" aria-label="Permalink to &quot;Chapter Overview&quot;">​</a></h2><p>This chapter introduces all communication channels and platforms supported by Clawdbot, including instant messaging apps (WhatsApp, Telegram, Slack, Discord, etc.), mobile nodes (iOS, Android), and desktop applications (macOS). Learn how to configure these channels to seamlessly integrate your AI assistant into your daily workflow.</p><h2 id="subpage-navigation" tabindex="-1">Subpage Navigation <a class="header-anchor" href="#subpage-navigation" aria-label="Permalink to &quot;Subpage Navigation&quot;">​</a></h2><h3 id="channel-overview" tabindex="-1">Channel Overview <a class="header-anchor" href="#channel-overview" aria-label="Permalink to &quot;Channel Overview&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">Multi-Channel System Overview</a></strong> - Learn about all communication channels supported by Clawdbot and their features, and master the basic concepts of channel configuration.</li></ul><h3 id="instant-messaging-channels" tabindex="-1">Instant Messaging Channels <a class="header-anchor" href="#instant-messaging-channels" aria-label="Permalink to &quot;Instant Messaging Channels&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - Configure and use the WhatsApp channel (based on Baileys), supporting device linking and group management.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Configure and use the Telegram channel (based on grammY Bot API), setting up Bot Token and Webhook.</li><li><strong><a href="./slack/">Slack</a></strong> - Configure and use the Slack channel (based on Bolt), integrating into your workspace.</li><li><strong><a href="./discord/">Discord</a></strong> - Configure and use the Discord channel (based on discord.js), supporting servers and channels.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Configure and use the Google Chat channel, integrating with Google Workspace.</li><li><strong><a href="./signal/">Signal</a></strong> - Configure and use the Signal channel (based on signal-cli), for privacy-protected communication.</li><li><strong><a href="./imessage/">iMessage</a></strong> - Configure and use the iMessage channel (macOS exclusive), integrating with the macOS Messages app.</li><li><strong><a href="./line/">LINE</a></strong> - Configure and use the LINE channel (Messaging API), interacting with LINE users.</li></ul><h3 id="web-and-native-apps" tabindex="-1">Web and Native Apps <a class="header-anchor" href="#web-and-native-apps" aria-label="Permalink to &quot;Web and Native Apps&quot;">​</a></h3><ul><li><strong><a href="./webchat/">WebChat Interface</a></strong> - Use the built-in WebChat interface to interact with your AI assistant without configuring external channels.</li><li><strong><a href="./macos-app/">macOS Application</a></strong> - Learn about the macOS menu bar app features, including Voice Wake, Talk Mode, and remote control.</li><li><strong><a href="./ios-node/">iOS Node</a></strong> - Configure the iOS node to perform device-local operations (Camera, Canvas, Voice Wake).</li><li><strong><a href="./android-node/">Android Node</a></strong> - Configure the Android node to perform device-local operations (Camera, Canvas).</li></ul><h2 id="recommended-learning-path" tabindex="-1">Recommended Learning Path <a class="header-anchor" href="#recommended-learning-path" aria-label="Permalink to &quot;Recommended Learning Path&quot;">​</a></h2><p>Based on your use case, we recommend the following learning order:</p><h3 id="quick-start-for-beginners" tabindex="-1">Quick Start for Beginners <a class="header-anchor" href="#quick-start-for-beginners" aria-label="Permalink to &quot;Quick Start for Beginners&quot;">​</a></h3><p>If you&#39;re using Clawdbot for the first time, we recommend learning in the following order:</p><ol><li><strong><a href="./channels-overview/">Multi-Channel System Overview</a></strong> - First, understand the overall architecture and channel concepts</li><li><strong><a href="./webchat/">WebChat Interface</a></strong> - The simplest way, no configuration required to get started</li><li><strong>Choose a Common Channel</strong> - Select based on your daily habits: <ul><li>Daily chat → <a href="./whatsapp/">WhatsApp</a> or <a href="./telegram/">Telegram</a></li><li>Team collaboration → <a href="./slack/">Slack</a> or <a href="./discord/">Discord</a></li><li>macOS users → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="mobile-integration" tabindex="-1">Mobile Integration <a class="header-anchor" href="#mobile-integration" aria-label="Permalink to &quot;Mobile Integration&quot;">​</a></h3><p>If you want to use Clawdbot on your phone:</p><ol><li><strong><a href="./ios-node/">iOS Node</a></strong> - Configure local functionality on iPhone/iPad</li><li><strong><a href="./android-node/">Android Node</a></strong> - Configure local functionality on Android devices</li><li><strong><a href="./macos-app/">macOS Application</a></strong> - Use the macOS app as a control center</li></ol><h3 id="enterprise-deployment" tabindex="-1">Enterprise Deployment <a class="header-anchor" href="#enterprise-deployment" aria-label="Permalink to &quot;Enterprise Deployment&quot;">​</a></h3><p>If you need to deploy in a team environment:</p><ol><li><strong><a href="./slack/">Slack</a></strong> - Integrate with team workspaces</li><li><strong><a href="./discord/">Discord</a></strong> - Set up community servers</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Integrate with Google Workspace</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before starting this chapter, we recommend completing:</p><ul><li><strong><a href="./../start/getting-started/">Quick Start</a></strong> - Complete Clawdbot installation and basic configuration</li><li><strong><a href="./../start/onboarding-wizard/">Onboarding Wizard</a></strong> - Complete basic Gateway and channel setup through the wizard</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you&#39;ve already completed the onboarding wizard, some channels may already be configured automatically. You can skip duplicate configuration steps and directly explore advanced features for specific channels.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue exploring:</p><ul><li><strong><a href="./../advanced/models-auth/">AI Model and Authentication Configuration</a></strong> - Configure different AI model providers</li><li><strong><a href="./../advanced/session-management/">Session Management and Multi-Agent</a></strong> - Learn about session isolation and sub-agent collaboration</li><li><strong><a href="./../advanced/tools-browser/">Tool System</a></strong> - Use browser automation, command execution, and other tools</li></ul><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h2><details class="details custom-block"><summary>Can I use multiple channels simultaneously?</summary><p>Yes! Clawdbot supports enabling multiple channels at the same time. You can receive and send messages across different channels, all processed through the unified Gateway.</p></details><details class="details custom-block"><summary>Which channel is most recommended?</summary><p>It depends on your use case:</p><ul><li><strong>WebChat</strong> - Simplest, no configuration required</li><li><strong>WhatsApp</strong> - Suitable for chatting with friends and family</li><li><strong>Telegram</strong> - Stable Bot API, suitable for automated replies</li><li><strong>Slack/Discord</strong> - Suitable for team collaboration</li></ul></details><details class="details custom-block"><summary>Does configuring channels require payment?</summary><p>Most channels themselves are free, but some channels may have costs:</p><ul><li>WhatsApp Business API - May incur fees</li><li>Google Chat - Requires a Google Workspace account</li><li>Other channels - Usually free, just need to apply for a Bot Token</li></ul></details>',33)])])}const m=a(i,[["render",r]]);export{g as __pageData,m as default};
